import { useEffect, useState, useMemo } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { useReactTable, getCoreRowModel, getSortedRowModel, flexRender } from '@tanstack/react-table';
import { fetchReservations, updateStatus } from '../features/reservations/reservationsSlice';
import { fetchWaitlist, notifyWaitlist } from '../features/waitlist/waitlistSlice';
import api from '../app/api';

const STATUSES = ['pending', 'confirmed', 'seated', 'completed', 'cancelled', 'no-show'];
const STATUS_COLORS = {
  confirmed: '#2ecc71', pending: '#f39c12', seated: '#3498db',
  completed: '#95a5a6', cancelled: '#e74c3c', 'no-show': '#c0392b',
};

export default function StaffDashboard() {
  const dispatch = useDispatch();
  const { data, total, pages, loading } = useSelector(s => s.reservations);
  const { entries } = useSelector(s => s.waitlist);
  const [filters, setFilters] = useState({ date: new Date().toISOString().split('T')[0], status: '', search: '', page: 1, sortBy: 'date', order: 'ASC' });
  const [sorting, setSorting] = useState([]);
  const [walkin, setWalkin] = useState({ tableId: '', guests: 2 });
  const [tables, setTables] = useState([]);

  useEffect(() => {
    dispatch(fetchReservations({ ...filters, limit: 10 }));
    dispatch(fetchWaitlist({ date: filters.date }));
  }, [filters]);

  useEffect(() => {
    api.get('/tables').then(r => setTables(r.data)).catch(() => {});
  }, []);

  // sync tanstack sorting -> filters
  useEffect(() => {
    if (sorting.length) {
      setFilters(f => ({ ...f, sortBy: sorting[0].id, order: sorting[0].desc ? 'DESC' : 'ASC', page: 1 }));
    }
  }, [sorting]);

  const columns = useMemo(() => [
    { accessorKey: 'customerName', header: 'Customer' },
    { accessorKey: 'date',         header: 'Date' },
    { accessorKey: 'time',         header: 'Time' },
    { accessorKey: 'guests',       header: 'Guests' },
    { accessorKey: 'status',       header: 'Status',
      cell: ({ getValue }) => (
        <span style={{ ...badge, background: STATUS_COLORS[getValue()] }}>{getValue()}</span>
      )
    },
    { id: 'actions', header: 'Actions', enableSorting: false,
      cell: ({ row }) => (
        <select defaultValue={row.original.status}
          onChange={e => dispatch(updateStatus({ id: row.original.id, status: e.target.value }))}
          style={{ padding: '4px', borderRadius: 4 }}>
          {STATUSES.map(s => <option key={s} value={s}>{s}</option>)}
        </select>
      )
    },
  ], []);

  const table = useReactTable({
    data,
    columns,
    state: { sorting },
    onSortingChange: setSorting,
    getCoreRowModel: getCoreRowModel(),
    getSortedRowModel: getSortedRowModel(),
    manualSorting: true,
  });

  const handleWalkin = async e => {
    e.preventDefault();
    await api.post('/reservations/walkin', walkin);
    dispatch(fetchReservations({ ...filters, limit: 10 }));
  };

  return (
    <div style={styles.wrap}>
      <h2>Staff Dashboard</h2>

      {/* Filters */}
      <div style={styles.filters}>
        <input style={styles.input} type="date" value={filters.date}
          onChange={e => setFilters({ ...filters, date: e.target.value, page: 1 })} />
        <input style={styles.input} placeholder="Search customer..." value={filters.search}
          onChange={e => setFilters({ ...filters, search: e.target.value, page: 1 })} />
        <select style={styles.input} value={filters.status}
          onChange={e => setFilters({ ...filters, status: e.target.value, page: 1 })}>
          <option value="">All Statuses</option>
          {STATUSES.map(s => <option key={s} value={s}>{s}</option>)}
        </select>
      </div>

      {/* TanStack Table */}
      {loading ? <p>Loading...</p> : (
        <>
          <p style={{ color: '#666' }}>{total} total</p>
          <div style={{ overflowX: 'auto' }}>
            <table style={styles.table}>
              <thead>
                {table.getHeaderGroups().map(hg => (
                  <tr key={hg.id}>
                    {hg.headers.map(h => (
                      <th key={h.id} style={styles.th}
                        onClick={h.column.getCanSort() ? h.column.getToggleSortingHandler() : undefined}
                        title={h.column.getCanSort() ? 'Sort' : ''}>
                        {flexRender(h.column.columnDef.header, h.getContext())}
                        {h.column.getIsSorted() === 'asc' ? ' ↑' : h.column.getIsSorted() === 'desc' ? ' ↓' : ''}
                      </th>
                    ))}
                  </tr>
                ))}
              </thead>
              <tbody>
                {table.getRowModel().rows.map(row => (
                  <tr key={row.id} style={styles.tr}>
                    {row.getVisibleCells().map(cell => (
                      <td key={cell.id} style={styles.td}>
                        {flexRender(cell.column.columnDef.cell, cell.getContext())}
                      </td>
                    ))}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
          <div style={styles.pagination}>
            {Array.from({ length: pages }, (_, i) => (
              <button key={i} style={{ ...styles.pageBtn, fontWeight: filters.page === i+1 ? 'bold' : 'normal' }}
                onClick={() => setFilters({ ...filters, page: i+1 })}>{i+1}</button>
            ))}
          </div>
        </>
      )}

      {/* Walk-in */}
      <h3 style={{ marginTop: 32 }}>Add Walk-in</h3>
      <form onSubmit={handleWalkin} style={styles.filters}>
        <select style={styles.input} value={walkin.tableId}
          onChange={e => setWalkin({ ...walkin, tableId: e.target.value })} required>
          <option value="">Select Table</option>
          {tables.map(t => <option key={t.id} value={t.id}>Table {t.number} (cap {t.capacity})</option>)}
        </select>
        <input style={styles.input} type="number" min="1" placeholder="Guests"
          value={walkin.guests} onChange={e => setWalkin({ ...walkin, guests: parseInt(e.target.value) })} />
        <button style={styles.btn} type="submit">Seat Walk-in</button>
      </form>

      {/* Waitlist */}
      <h3 style={{ marginTop: 32 }}>Waitlist — {filters.date}</h3>
      {entries.length === 0 ? <p>No waitlist entries.</p> : entries.map(e => (
        <div key={e.id} style={styles.wCard}>
          <span>{e.customerName} — {e.guests} guests</span>
          {!e.notified && (
            <button style={styles.notifyBtn} onClick={() => dispatch(notifyWaitlist(e.id))}>Notify</button>
          )}
          {e.notified && <span style={{ color: 'green' }}>✓ Notified</span>}
        </div>
      ))}
    </div>
  );
}

const badge = { color: '#fff', padding: '2px 8px', borderRadius: 10, fontSize: '0.8rem' };
const styles = {
  wrap:       { maxWidth: 1100, margin: '32px auto', padding: '0 16px' },
  filters:    { display: 'flex', gap: 12, marginBottom: 16, flexWrap: 'wrap' },
  input:      { padding: '8px', border: '1px solid #ddd', borderRadius: 4, fontSize: '0.95rem', flex: 1, minWidth: 140 },
  btn:        { padding: '8px 18px', background: '#e94560', color: '#fff', border: 'none', borderRadius: 4, cursor: 'pointer' },
  table:      { width: '100%', borderCollapse: 'collapse', background: '#fff', borderRadius: 8, overflow: 'hidden', boxShadow: '0 1px 6px rgba(0,0,0,0.08)' },
  th:         { padding: '12px 16px', background: '#1a1a2e', color: '#fff', textAlign: 'left', cursor: 'pointer', userSelect: 'none' },
  tr:         { borderBottom: '1px solid #f0f0f0' },
  td:         { padding: '10px 16px' },
  pagination: { display: 'flex', gap: 8, marginTop: 16 },
  pageBtn:    { padding: '6px 12px', border: '1px solid #ddd', borderRadius: 4, cursor: 'pointer', background: '#fff' },
  wCard:      { display: 'flex', justifyContent: 'space-between', alignItems: 'center', background: '#fff', padding: '12px 16px', borderRadius: 8, marginBottom: 8, boxShadow: '0 1px 4px rgba(0,0,0,0.06)' },
  notifyBtn:  { padding: '5px 12px', background: '#3498db', color: '#fff', border: 'none', borderRadius: 4, cursor: 'pointer' },
};
